/**
 * @summary Delete a remedy log session
 */
export const getDeleteSessionUrl = (id: number) => {
  return `/api/sessions/${id}`;
};

export const deleteSession = async (
  id: number,
  options?: RequestInit,
): Promise<void> => {
  return customFetch<void>(getDeleteSessionUrl(id), {
    ...options,
    method: "DELETE",
  });
};

